CREATE OR REPLACE FUNCTION fpb_acc_get_jv_amt_not ( as_accid char , adtm_bdate timestamp(0), adtm_edate timestamp(0) , as_nature char ) RETURNS bigint AS $body$
DECLARE

ldc_dr bigint;
ldc_cr bigint;


BEGIN

    select  sum(jd.dr_amount) , sum(jd.cr_amount)
    into STRICT    ldc_dr , ldc_cr 
    from sc_acc_journal_detail_firm jd
    ,sc_acc_journal_heading_firm  jh   
    where 1=1
    and  jh.doc_no = jd.doc_no    
    and jd.doc_type != 'JV'
    and jh.cancel_status  = '0'    
    and jh.journal_date between adtm_bdate and adtm_edate   
    and jd.account_id = as_accid
;

    case trim(both upper( as_nature ))
    when 'DR' then
      if coalesce(ldc_dr::text, '') = '' then ldc_dr := 0;end if;

      return ldc_dr;
    when 'CR' then
      if coalesce(ldc_cr::text, '') = '' then ldc_cr := 0;end if;
      return ldc_cr;
     else
      return 0;
    end case;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
